// bundle-fingers.cjs — собирает IIFE-модули Fingers в один heys_fingers_bundle_v1.js
// для сокращения множества sequential <script> requests до 1 file load.
//
// Запуск:
//   node apps/web/scripts/bundle-fingers.cjs       — пересобрать bundle
//   pnpm bundle:fingers                            — через package.json script
//
// Источники: apps/web/fingers/*.js (порядок строго фиксирован — он же используется
// и в heys_day_stats_bundle_loader_v1.js как documentation что от чего зависит).
//
// Output: apps/web/heys_fingers_bundle_v1.js (auto-generated, не редактируй вручную).

const fs = require('fs');
const path = require('path');

const ROOT = process.cwd();
const SRC_DIR = path.join(ROOT, 'fingers');
const OUT_FILE = path.join(ROOT, 'heys_fingers_bundle_v1.js');

// Порядок зависимостей. Если добавляешь новый модуль — впиши его в правильное
// место по dependency-уровню. Order matters: IIFE-модули регистрируются
// в `HEYS.Fingers.*` строго sequential; consumer-модули ниже по списку
// предполагают что upstream API уже на месте.
const MODULES = [
    // ── Layer 1: core data + features (no fingers deps) ──
    { file: 'heys_fingers_audio_extension_v1.js', label: 'audio capability' },
    { file: 'heys_fingers_body_metrics_v1.js',    label: 'body weight resolver' },
    { file: 'heys_fingers_profile_store_v1.js',   label: 'shared fingers profile store' },
    { file: 'heys_fingers_bibliography_v1.js',    label: 'sources + SourceBadge' },
    { file: 'heys_fingers_grips_catalog_v1.js',   label: 'grip catalog' },
    { file: 'heys_fingers_boards_catalog_v1.js',  label: 'fingerboard catalog' },
    { file: 'heys_fingers_programs_catalog_v1.js',label: 'protocol catalog' },
    { file: 'heys_fingers_quality_catalog_v1.js', label: 'methodology data layer (9 qualities)' },
    { file: 'heys_fingers_block_catalog_v1.js',   label: '36 atoms × 9 blocks (METHODOLOGY ч.4)' },
    { file: 'heys_fingers_validators_v1.js',      label: 'safety validators S1–S8 + homed V_*' },
    { file: 'heys_fingers_progression_v1.js',     label: 'B3 — detectPlateau + axes policy (§1.2/1.3)' },
    { file: 'heys_fingers_assessment_v1.js',      label: 'limiter scoring §3.2 (deficit × flag × prior)' },
    { file: 'heys_fingers_age_gating_v1.js',      label: 'UIAA/BMC age gate' },
    { file: 'heys_fingers_readiness_v1.js',       label: 'readiness assess' },

    // ── Layer 2: visuals + voice ──
    { file: 'heys_fingers_svg_grips_v1.js',       label: 'grip SVG' },
    { file: 'heys_fingers_svg_anatomy_v1.js',     label: 'anatomy SVG' },
    { file: 'heys_fingers_voice_v1.js',           label: 'voice phrase bank' },

    // ── Layer 3: logic (records → calibration → timer → persistence) ──
    { file: 'heys_fingers_records_store_v1.js',   label: 'MVC/records store' },
    { file: 'heys_fingers_calibration_v1.js',     label: 'max-hang calibration' },
    { file: 'heys_fingers_timer_v1.js',           label: 'countdown timer' },
    { file: 'heys_fingers_session_persistence_v1.js', label: 'snapshot save/restore' },
    { file: 'heys_fingers_calendar_v1.js',        label: 'year heatmap' },
    { file: 'heys_fingers_safety_v1.js',          label: 'RAMP-warmup defs' },
    { file: 'heys_fingers_warmup_runner_v1.js',   label: 'warmup runner' },
    { file: 'heys_fingers_mix_engine_v1.js',      label: 'role-based mix engine' },
    { file: 'heys_fingers_periodization_engine_v1.js', label: 'periodization planner' },
    { file: 'heys_fingers_session_builder_v1.js', label: 'new engine — block_catalog→session' },
    { file: 'heys_fingers_engine_router_v1.js',   label: 'strangler router (flag-gated)' },

    // ── Layer 4: UI (depends on all above) ──
    { file: 'heys_fingers_muscle_detail_v1.js',   label: 'muscle drill-down' },
    { file: 'heys_fingers_constructor_v1.js',     label: 'exercise editor' },
    { file: 'heys_fingers_onboarding_v1.js',      label: 'wizard' },
    { file: 'heys_fingers_session_ui_v1.js',      label: '4-tab UI' },
    { file: 'heys_fingers_fullscreen_v1.js',      label: 'portal orchestrator' },

    // ── Layer 5: entry — exposes public API (must be LAST) ──
    { file: 'heys_fingers_entry_v1.js',           label: 'public API' },
];

const banner = [
    '// heys_fingers_bundle_v1.js — bundled Fingers module (climbing fingerboard).',
    '// ⚠️ Auto-generated by apps/web/scripts/bundle-fingers.cjs. Do not edit manually.',
    '// Source files: apps/web/fingers/heys_fingers_*_v1.js (' + MODULES.length + ' modules).',
    '// Order is dependency-driven — see bundle-fingers.cjs MODULES list for layers.',
    ''
].join('\n');

const chunks = [banner];
const missing = [];

for (const mod of MODULES) {
    const srcPath = path.join(SRC_DIR, mod.file);
    if (!fs.existsSync(srcPath)) {
        missing.push(mod.file);
        continue;
    }
    const raw = fs.readFileSync(srcPath, 'utf8').trimEnd();
    // Каждый модуль завёрнут в собственный IIFE — leading `;` страхует от
    // ASI-ловушек когда предыдущий файл не оканчивается `;`.
    const safe = raw.startsWith(';') ? raw : ';' + raw;
    chunks.push('// ===== Begin ' + mod.file + ' — ' + mod.label + ' =====');
    chunks.push(safe);
    chunks.push('// ===== End ' + mod.file + ' =====');
    chunks.push('');
}

if (missing.length) {
    console.error('[bundle-fingers] ❌ Missing source files:');
    for (const f of missing) console.error('  - apps/web/fingers/' + f);
    process.exit(1);
}

fs.writeFileSync(OUT_FILE, chunks.join('\n'), 'utf8');

const sizeKB = (fs.statSync(OUT_FILE).size / 1024).toFixed(1);
console.info('[bundle-fingers] ✅ ' + MODULES.length + ' modules → heys_fingers_bundle_v1.js (' + sizeKB + ' KB)');
